import { useEffect } from 'react';
import { Outlet, useNavigate } from 'react-router-dom';
import AdminSidebar from '../components/AdminSidebar';

function DashboardLayout() {
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const navigate = useNavigate();

  useEffect(() => {
    if (!token) { navigate('/login'); return; }
    if (user.role !== 'admin') navigate('/home');
  }, []);

  if (!token || user.role !== 'admin') return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#fdf6f3' }}>
      <p style={{ color: '#c9a99a' }}>Checking permissions...</p>
    </div>
  );

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#fdf6f3' }}>
      <AdminSidebar />
      <main style={{ flex: 1, overflow: 'hidden' }}><Outlet /></main>
    </div>
  );
}
export default DashboardLayout;
